1	/*
2	 ============================================================================
3	 Name        : 2048.c
4	 Author      : Maurits van der Schee
5	 Description : Console version of the game "2048" for GNU/Linux
6	 ============================================================================
7	 */
8	
9	#define VERSION "1.0.3"
10	
11	#define _XOPEN_SOURCE 500 // for: usleep
12	#include <stdio.h>		  // defines: printf, puts, getchar
13	#include <stdlib.h>		  // defines: EXIT_SUCCESS
14	#include <string.h>		  // defines: strcmp
15	#include <unistd.h>		  // defines: STDIN_FILENO, usleep
16	#include <termios.h>	  // defines: termios, TCSANOW, ICANON, ECHO
17	#include <stdbool.h>	  // defines: true, false
18	#include <stdint.h>		  // defines: uint8_t, uint32_t
19	#include <time.h>		  // defines: time
20	#include <signal.h>		  // defines: signal, SIGINT
21	
22	#define SIZE 4
23	
24	// this function receives 2 pointers (indicated by *) so it can set their values
25	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
26	{
27		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
28		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
29		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
30		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
31		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
32		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
33		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
34		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
35		// alternatively we could have returned a struct with two variables
36	}
37	
38	uint8_t getDigitCount(uint32_t number)
39	{
40		uint8_t count = 0;
41		do
42		{
43			number /= 10;
44			count += 1;
45		} while (number);
46		return count;
47	}
48	
49	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
50	{
51		uint8_t x, y, fg, bg;
52		printf("\033[H"); // move cursor to 0,0
53		printf("2048.c %17u pts\n\n", score);
54		for (y = 0; y < SIZE; y++)
55		{
56			for (x = 0; x < SIZE; x++)
57			{
58				// send the addresses of the foreground and background variables,
59				// so that they can be modified by the getColors function
60				getColors(board[x][y], scheme, &fg, &bg);
61				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
62				printf("       ");
63				printf("\033[m"); // reset all modes
64			}
65			printf("\n");
66			for (x = 0; x < SIZE; x++)
67			{
68				getColors(board[x][y], scheme, &fg, &bg);
69				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
70				if (board[x][y] != 0)
71				{
72					uint32_t number = 1 << board[x][y];
73					uint8_t t = 7 - getDigitCount(number);
74					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
75				}
76				else
77				{
78					printf("   ·   ");
79				}
80				printf("\033[m"); // reset all modes
81			}
82			printf("\n");
83			for (x = 0; x < SIZE; x++)
84			{
85				getColors(board[x][y], scheme, &fg, &bg);
86				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
87				printf("       ");
88				printf("\033[m"); // reset all modes
89			}
90			printf("\n");
91		}
92		printf("\n");
93		printf("        ←,↑,→,↓ or q        \n");
94		printf("\033[A"); // one line up
95	}
96	
97	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
98	{
99		uint8_t t;
100		// if the position is already on the first, don't evaluate
101		if (x == 0)
102		{
103			return x;
104		}
105		for (t = x - 1;; t--)
106		{
107			if (array[t] != 0)
108			{
109				if (array[t] != array[x])
110				{
111					// merge is not possible, take next position
112					return t + 1;
113				}
114				return t;
115			}
116			else
117			{
118				// we should not slide further, return this one
119				if (t == stop)
120				{
121					return t;
122				}
123			}
124		}
125		// we did not find a target
126		return x;
127	}
128	
129	bool slideArray(uint8_t array[SIZE], uint32_t *score)
130	{
131		bool success = false;
132		uint8_t x, t, stop = 0;
133	
134		for (x = 0; x < SIZE; x++)
135		{
136			if (array[x] != 0)
137			{
138				t = findTarget(array, x, stop);
139				// if target is not original position, then move or merge
140				if (t != x)
141				{
142					// if target is zero, this is a move
143					if (array[t] == 0)
144					{
145						array[t] = array[x];
146					}
147					else if (array[t] == array[x])
148					{
149						// merge (increase power of two)
150						array[t]++;
151						// increase score
152						*score += 1 << array[t];
153						// set stop to avoid double merge
154						stop = t + 1;
155					}
156					array[x] = 0;
157					success = true;
158				}
159			}
160		}
161		return success;
162	}
163	
164	void rotateBoard(uint8_t board[SIZE][SIZE])
165	{
166		uint8_t i, j, n = SIZE;
167		uint8_t tmp;
168		for (i = 0; i < n / 2; i++)
169		{
170			for (j = i; j < n - i - 1; j++)
171			{
172				tmp = board[i][j];
173				board[i][j] = board[j][n - i - 1];
174				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
175				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
176				board[n - j - 1][i] = tmp;
177			}
178		}
179	}
180	
181	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
182	{
183		bool success = false;
184		uint8_t x;
185		for (x = 0; x < SIZE; x++)
186		{
187			success |= slideArray(board[x], score);
188		}
189		return success;
190	}
191	
192	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
193	{
194		bool success;
195		rotateBoard(board);
196		success = moveUp(board, score);
197		rotateBoard(board);
198		rotateBoard(board);
199		rotateBoard(board);
200		return success;
201	}
202	
203	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
204	{
205		bool success;
206		rotateBoard(board);
207		rotateBoard(board);
208		success = moveUp(board, score);
209		rotateBoard(board);
210		rotateBoard(board);
211		return success;
212	}
213	
214	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
215	{
216		bool success;
217		rotateBoard(board);
218		rotateBoard(board);
219		rotateBoard(board);
220		success = moveUp(board, score);
221		rotateBoard(board);
222		return success;
223	}
224	
225	bool findPairDown(uint8_t board[SIZE][SIZE])
226	{
227		bool success = false;
228		uint8_t x, y;
229		for (x = 0; x < SIZE; x++)
230		{
231			for (y = 0; y < SIZE - 1; y++)
232			{
233				if (board[x][y] == board[x][y + 1])
234					return true;
235			}
236		}
237		return success;
238	}
239	
240	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
241	{
242		uint8_t x, y;
243		uint8_t count = 0;
244		for (x = 0; x < SIZE; x++)
245		{
246			for (y = 0; y < SIZE; y++)
247			{
248				if (board[x][y] == 0)
249				{
250					count++;
251				}
252			}
253		}
254		return count;
255	}
256	
257	bool gameEnded(uint8_t board[SIZE][SIZE])
258	{
259		bool ended = true;
260		if (countEmpty(board) > 0)
261			return false;
262		if (findPairDown(board))
263			return false;
264		rotateBoard(board);
265		if (findPairDown(board))
266			ended = false;
267		rotateBoard(board);
268		rotateBoard(board);
269		rotateBoard(board);
270		return ended;
271	}
272	
273	void addRandom(uint8_t board[SIZE][SIZE])
274	{
275		static bool initialized = false;
276		uint8_t x, y;
277		uint8_t r, len = 0;
278		uint8_t n, list[SIZE * SIZE][2];
279	
280		if (!initialized)
281		{
282			srand(time(NULL));
283			initialized = true;
284		}
285	
286		for (x = 0; x < SIZE; x++)
287		{
288			for (y = 0; y < SIZE; y++)
289			{
290				if (board[x][y] == 0)
291				{
292					list[len][0] = x;
293					list[len][1] = y;
294					len++;
295				}
296			}
297		}
298	
299		if (len > 0)
300		{
301			r = rand() % len;
302			x = list[r][0];
303			y = list[r][1];
304			n = (rand() % 10) / 9 + 1;
305			board[x][y] = n;
306		}
307	}
308	
309	void initBoard(uint8_t board[SIZE][SIZE])
310	{
311		uint8_t x, y;
312		for (x = 0; x < SIZE; x++)
313		{
314			for (y = 0; y < SIZE; y++)
315			{
316				board[x][y] = 0;
317			}
318		}
319		addRandom(board);
320		addRandom(board);
321	}
322	
323	void setBufferedInput(bool enable)
324	{
325		static bool enabled = true;
326		static struct termios old;
327		struct termios new;
328	
329		if (enable && !enabled)
330		{
331			// restore the former settings
332			tcsetattr(STDIN_FILENO, TCSANOW, &old);
333			// set the new state
334			enabled = true;
335		}
336		else if (!enable && enabled)
337		{
338			// get the terminal settings for standard input
339			tcgetattr(STDIN_FILENO, &new);
340			// we want to keep the old setting to restore them at the end
341			old = new;
342			// disable canonical mode (buffered i/o) and local echo
343			new.c_lflag &= (~ICANON & ~ECHO);
344			// set the new settings immediately
345			tcsetattr(STDIN_FILENO, TCSANOW, &new);
346			// set the new state
347			enabled = false;
348		}
349	}
350	
351	bool testSucceed()
352	{
353		uint8_t array[SIZE];
354		// these are exponents with base 2 (1=2 2=4 3=8)
355		// data holds per line: 4x IN, 4x OUT, 1x POINTS
356		uint8_t data[] = {
357			0, 0, 0, 1, 1, 0, 0, 0, 0,
358			0, 0, 1, 1, 2, 0, 0, 0, 4,
359			0, 1, 0, 1, 2, 0, 0, 0, 4,
360			1, 0, 0, 1, 2, 0, 0, 0, 4,
361			1, 0, 1, 0, 2, 0, 0, 0, 4,
362			1, 1, 1, 0, 2, 1, 0, 0, 4,
363			1, 0, 1, 1, 2, 1, 0, 0, 4,
364			1, 1, 0, 1, 2, 1, 0, 0, 4,
365			1, 1, 1, 1, 2, 2, 0, 0, 8,
366			2, 2, 1, 1, 3, 2, 0, 0, 12,
367			1, 1, 2, 2, 2, 3, 0, 0, 12,
368			3, 0, 1, 1, 3, 2, 0, 0, 4,
369			2, 0, 1, 1, 2, 2, 0, 0, 4};
370		uint8_t *in, *out, *points;
371		uint8_t t, tests;
372		uint8_t i;
373		bool success = true;
374		uint32_t score;
375	
376		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
377		for (t = 0; t < tests; t++)
378		{
379			in = data + t * (2 * SIZE + 1);
380			out = in + SIZE;
381			points = in + 2 * SIZE;
382			for (i = 0; i < SIZE; i++)
383			{
384				array[i] = in[i];
385			}
386			score = 0;
387			slideArray(array, &score);
388			for (i = 0; i < SIZE; i++)
389			{
390				if (array[i] != out[i])
391				{
392					success = false;
393				}
394			}
395			if (score != *points)
396			{
397				success = false;
398			}
399			if (success == false)
400			{
401				for (i = 0; i < SIZE; i++)
402				{
403					printf("%u ", in[i]);
404				}
405				printf("=> ");
406				for (i = 0; i < SIZE; i++)
407				{
408					printf("%u ", array[i]);
409				}
410				printf("(%u points) expected ", score);
411				for (i = 0; i < SIZE; i++)
412				{
413					printf("%u ", in[i]);
414				}
415				printf("=> ");
416				for (i = 0; i < SIZE; i++)
417				{
418					printf("%u ", out[i]);
419				}
420				printf("(%u points)\n", *points);
421				break;
422			}
423		}
424		if (success)
425		{
426			printf("All %u tests executed successfully\n", tests);
427		}
428		return success;
429	}
430	
431	void signal_callback_handler(int signum)
432	{
433		printf("         TERMINATED         \n");
434		setBufferedInput(true);
435		// make cursor visible, reset all modes
436		printf("\033[?25h\033[m");
437		exit(signum);
438	}
439	
440	int main(int argc, char *argv[])
441	{
442		uint8_t board[SIZE][SIZE];
443		uint8_t scheme = 0;
444		uint32_t score = 0;
445		int c;
446		bool success;
447	
448		// handle the command line options
449		if (argc > 1)
450		{
451			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
452			{
453				printf("Usage: 2048 [OPTION] | [MODE]\n");
454				printf("Play the game 2048 in the console\n\n");
455				printf("Options:\n");
456				printf("  -h,  --help       Show this help message.\n");
457				printf("  -v,  --version    Show version number.\n\n");
458				printf("Modes:\n");
459				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
460				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
461				return EXIT_SUCCESS;
462			}
463			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
464			{
465				printf("2048.c version %s\n", VERSION);
466				return EXIT_SUCCESS;
467			}
468			else if (strcmp(argv[1], "blackwhite") == 0)
469			{
470				scheme = 1;
471			}
472			else if (strcmp(argv[1], "bluered") == 0)
473			{
474				scheme = 2;
475			}
476			else if (strcmp(argv[1], "whiteblack") == 0)
477			{
478				scheme = 3;
479			}
480			else if (strcmp(argv[1], "test") == 0)
481			{
482				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
483			}
484			else
485			{
486				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
487				return EXIT_FAILURE;
488			}
489		}
490	
491		// make cursor invisible, erase entire screen
492		printf("\033[?25l\033[2J");
493	
494		// register signal handler for when ctrl-c is pressed
495		signal(SIGINT, signal_callback_handler);
496	
497		initBoard(board);
498		setBufferedInput(false);
499		drawBoard(board, scheme, score);
500		while (true)
501		{
502			c = getchar();
503			if (c == EOF)
504			{
505				puts("\nError! Cannot read keyboard input!");
506				break;
507			}
508			switch (c)
509			{
510			case 52:  // '4' key
511			case 97:  // 'a' key
512			case 104: // 'h' key
513			case 68:  // left arrow
514				success = moveLeft(board, &score);
515				break;
516			case 54:  // '6' key
517			case 100: // 'd' key
518			case 108: // 'l' key
519			case 67:  // right arrow
520				success = moveRight(board, &score);
521				break;
522			case 56:  // '8' key
523			case 119: // 'w' key
524			case 107: // 'k' key
525			case 65:  // up arrow
526				success = moveUp(board, &score);
527				break;
528			case 50:  // '2' key
529			case 115: // 's' key
530			case 106: // 'j' key
531			case 66:  // down arrow
532				success = moveDown(board, &score);
533				break;
534			default:
535				success = false;
536			}
537			if (success)
538			{
539				drawBoard(board, scheme, score);
540				usleep(150 * 1000); // 150 ms
541				addRandom(board);
542				drawBoard(board, scheme, score);
543				if (gameEnded(board))
544				{
545					printf("         GAME OVER          \n");
546					break;
547				}
548			}
549			if (c == 'q')
550			{
551				printf("        QUIT? (y/n)         \n");
552				c = getchar();
553				if (c == 'y')
554				{
555					break;
556				}
557				drawBoard(board, scheme, score);
558			}
559			if (c == 'r')
560			{
561				printf("       RESTART? (y/n)       \n");
562				c = getchar();
563				if (c == 'y')
564				{
565					initBoard(board);
566					score = 0;
567				}
568				drawBoard(board, scheme, score);
569			}
570		}
571		setBufferedInput(true);
572	
573		// make cursor visible, reset all modes
574		printf("\033[?25h\033[m");
575	
576		return EXIT_SUCCESS;
577	}
